export function nextGeneration(cells: Cell[]): Cell[] {
  const isLive = (x: number, y: number): boolean =>
    cells.some(([cx, cy]) => cx === x && cy === y);

  const countLiveNeighbors = (x: number, y: number): number =>
    NEIGHBOR_OFFSETS.filter(([dx, dy]) => isLive(x + dx, y + dy)).length;

  const survives = (neighbors: number): boolean =>
    neighbors === 2 || neighbors === 3;

  const neighborsOf = ([x, y]: Cell): Cell[] =>
    NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);

  const uniqueCells = (all: Cell[]): Cell[] =>
    Array.from(new Map(all.map((c) => [`${c[0]},${c[1]}`, c])).values());

  const survivors = cells.filter(([x, y]) => survives(countLiveNeighbors(x, y)));

  const deadNeighbors = uniqueCells(cells.flatMap(neighborsOf))
    .filter(([x, y]) => !isLive(x, y));

  const births = deadNeighbors.filter(([x, y]) => countLiveNeighbors(x, y) === 3);

  return [...survivors, ...births];
}

